export const CONTENT_HTML = "\r\n<p class=\"intro\">Có bao giờ bạn nhìn một tác phẩm và thấy nó \"đẹp\" mà không giải thích được tại sao? Ngược lại, có bức thấy \"sai sai\" mà không nói rõ sai ở đâu? Đó chính là lúc <strong>nguyên lý thị giác</strong> đang hoạt động âm thầm trong đầu bạn.</p>\r\n\r\n<div class=\"stats break-half\">\r\n  <div class=\"stat\"><div class=\"stat-num\">6</div><div class=\"stat-label\">Nguyên lý cốt lõi</div><div class=\"stat-sub\">Của thị giác con người</div></div>\r\n  <div class=\"stat\"><div class=\"stat-num\">100%</div><div class=\"stat-label\">Mọi tác phẩm</div><div class=\"stat-sub\">Đều tuân theo</div></div>\r\n  <div class=\"stat\"><div class=\"stat-num\">1920s</div><div class=\"stat-label\">Hình thành</div><div class=\"stat-sub\">Trường phái Gestalt</div></div>\r\n</div>\r\n\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>01</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Định nghĩa</p>\r\n    <h2 class=\"div-title\">Nguyên lý thị giác là gì?</h2>\r\n  </div>\r\n</div>\r\n\r\n<p><strong>Nguyên lý thị giác</strong> <em>(Visual Principles / Gestalt Principles)</em> là tập hợp các quy luật mô tả cách mắt và não người tổ chức, nhận diện hình ảnh. Chúng được khám phá từ đầu thế kỷ 20 bởi trường phái tâm lý học Gestalt của Đức.</p>\r\n\r\n<p>Điểm đặc biệt: những nguyên lý này <strong>không phải quy ước văn hóa</strong>. Chúng gắn với sinh học của mắt và não — áp dụng cho mọi người, mọi nền văn hóa, mọi thời đại.</p>\r\n\r\n<!-- 🖼️ GALLERY-3 · 3 ví dụ Gestalt trong đời sống -->\r\n<div class=\"gallery gallery-3\">\r\n  <figure class=\"gallery-box\">\r\n    <img src=\"/img/nguyen-ly-thi-giac/gallery-3-1.jpg\" alt=\"Gestalt proximity\" loading=\"lazy\" decoding=\"async\" />\r\n  </figure>\r\n  <figure class=\"gallery-box\">\r\n    <img src=\"/img/nguyen-ly-thi-giac/gallery-3-2.jpg\" alt=\"Gestalt similarity\" loading=\"lazy\" decoding=\"async\" />\r\n  </figure>\r\n  <figure class=\"gallery-box\">\r\n    <img src=\"/img/nguyen-ly-thi-giac/gallery-3-3.jpg\" alt=\"Gestalt closure\" loading=\"lazy\" decoding=\"async\" />\r\n  </figure>\r\n</div>\r\n\r\n<div class=\"gls\">\r\n  <p class=\"gls-head\">A — Thuật ngữ Gestalt</p>\r\n  <div class=\"gls-body\">\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Gestalt<small>Tổng thể</small></p><p class=\"gls-def\">Nguyên tắc: tổng thể lớn hơn tổng các phần cộng lại.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Figure-Ground<small>Hình-Nền</small></p><p class=\"gls-def\">Khả năng mắt phân biệt đối tượng chính khỏi bối cảnh.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Closure<small>Khép kín</small></p><p class=\"gls-def\">Não tự điền vào phần thiếu để tạo hình hoàn chỉnh.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Proximity<small>Gần gũi</small></p><p class=\"gls-def\">Các yếu tố gần nhau được coi là 1 nhóm.</p></div>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>02</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Lý do</p>\r\n    <h2 class=\"div-title\">Tại sao quan trọng?</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Nguyên lý thị giác không dạy bạn <em>vẽ</em> — nó dạy bạn <strong>giải thích</strong>. Biết một bức tranh đẹp vì sao, biết bài mình sai ở đâu, biết đưa ra quyết định thiết kế có lý do thay vì chỉ \"thấy ổn\".</p>\r\n\r\n<div class=\"cmp break-half\">\r\n  <div class=\"cmp-col l\">\r\n    <p class=\"cmp-lbl\">Không hiểu nguyên lý</p>\r\n    <p class=\"cmp-title\">Dựa vào cảm giác</p>\r\n    <ul class=\"cmp-list\">\r\n      <li>Không giải thích được \"tại sao đẹp\"</li>\r\n      <li>Khó chỉnh sửa khi bài chưa ưng</li>\r\n      <li>Dễ bị influencer/trend chi phối</li>\r\n      <li>Khi đổi môi trường mới phải học lại từ đầu</li>\r\n    </ul>\r\n  </div>\r\n  <div class=\"cmp-col r\">\r\n    <p class=\"cmp-lbl\">Có nguyên lý</p>\r\n    <p class=\"cmp-title\">Có công cụ chẩn đoán</p>\r\n    <ul class=\"cmp-list\">\r\n      <li>Nhìn ra ngay vấn đề: cân bằng, tương phản</li>\r\n      <li>Sửa bài hiệu quả vì biết chỗ cần sửa</li>\r\n      <li>Tự tin bảo vệ quyết định thiết kế</li>\r\n      <li>Áp dụng được cho mọi môi trường — 2D, 3D, UI</li>\r\n    </ul>\r\n  </div>\r\n</div>\r\n\r\n<!-- 🖼️ BLEED-DUAL · So sánh 2 poster -->\r\n<div class=\"bleed-dual\">\r\n  <div class=\"bleed-box variant-a\">\r\n    <div class=\"bleed-img\"><img src=\"/img/nguyen-ly-thi-giac/bleed-a.jpg\" alt=\"Poster kh\u00f4ng d\u00f9ng nguy\u00ean l\u00fd\" loading=\"lazy\" /></div>\r\n  </div>\r\n  <div class=\"bleed-box variant-b\">\r\n    <div class=\"bleed-img\"><img src=\"/img/nguyen-ly-thi-giac/bleed-b.jpg\" alt=\"\u00c1p d\u1ee5ng nguy\u00ean l\u00fd\" loading=\"lazy\" /></div>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"pq\">\r\n  <p class=\"pq-text\">Nguyên lý thị giác là ngữ pháp chung của mắt người — không ai dạy, nhưng ai <em>cũng hiểu.</em></p>\r\n  <span class=\"pq-cite\">— Gestalt Psychology, 1920s</span>\r\n</div>\r\n\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>03</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Nguyên lý</p>\r\n    <h2 class=\"div-title\">6 nguyên lý cốt lõi</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Trong hàng chục nguyên lý Gestalt được mô tả, có 6 nguyên lý áp dụng trực tiếp nhất cho người làm mỹ thuật:</p>\r\n\r\n<div class=\"pr-table\">\r\n  <div class=\"pr-row\"><span class=\"pr-i\">i.</span><div class=\"pr-n\">Gần gũi<small>Proximity</small></div><div class=\"pr-d\">Các yếu tố đặt gần nhau được mắt tự nhóm thành một.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">ii.</span><div class=\"pr-n\">Tương đồng<small>Similarity</small></div><div class=\"pr-d\">Các yếu tố giống nhau về hình, màu, kích thước được coi là cùng loại.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">iii.</span><div class=\"pr-n\">Liên tục<small>Continuity</small></div><div class=\"pr-d\">Mắt theo đường cong, đường thẳng tự nhiên.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">iv.</span><div class=\"pr-n\">Khép kín<small>Closure</small></div><div class=\"pr-d\">Não tự điền vào phần thiếu của hình.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">v.</span><div class=\"pr-n\">Hình-Nền<small>Figure-Ground</small></div><div class=\"pr-d\">Khả năng phân biệt đối tượng chính khỏi bối cảnh.</div></div>\r\n  <div class=\"pr-row\"><span class=\"pr-i\">vi.</span><div class=\"pr-n\">Tiêu điểm<small>Focal Point</small></div><div class=\"pr-d\">Mắt luôn tìm điểm khác biệt để tập trung vào.</div></div>\r\n</div>\r\n\r\n<!-- 🖼️ GALLERY-4 · Minh hoạ 4 nguyên lý chính -->\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>04</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Ứng dụng</p>\r\n    <h2 class=\"div-title\">Dùng ở đâu trong bài?</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Nguyên lý thị giác không chỉ có trong tranh. Chúng hiện diện trong mọi quyết định thị giác bạn đưa ra:</p>\r\n\r\n<div class=\"el-intro\">\r\n  <div class=\"el-intro-n\">4</div>\r\n  <p class=\"el-intro-t\">Lĩnh vực chính nơi nguyên lý thị giác được ứng dụng hàng ngày.</p>\r\n</div>\r\n\r\n<div class=\"el-list\">\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\"><span class=\"el-n\">01</span><p class=\"el-name\">H\u1ed9i h\u1ecda <em>Painting</em></p><p class=\"el-desc\">B\u1ed1 c\u1ee5c tranh, d\u1eabn m\u1eaft ng\u01b0\u1eddi xem \u0111i qua c\u00e1c \u0111i\u1ec3m ch\u00ednh.</p></div>\r\n    <div class=\"el-item-img\" data-wipe><img src=\"/img/nguyen-ly-thi-giac/el-01-hoi-hoa.png\" alt=\"H\u1ed9i h\u1ecda\" loading=\"lazy\" decoding=\"async\" /></div>\r\n  </div>\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\"><span class=\"el-n\">02</span><p class=\"el-name\">Thi\u1ebft k\u1ebf <em>Design</em></p><p class=\"el-desc\">Poster, logo, UI/UX \u2014 quy\u1ebft \u0111\u1ecbnh th\u1ee9 t\u1ef1 ti\u1ebfp nh\u1eadn th\u00f4ng tin.</p></div>\r\n    <div class=\"el-item-img\" data-wipe><img src=\"/img/nguyen-ly-thi-giac/el-02-poster-design.png\" alt=\"Thi\u1ebft k\u1ebf\" loading=\"lazy\" decoding=\"async\" /></div>\r\n  </div>\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\"><span class=\"el-n\">03</span><p class=\"el-name\">Ho\u1ea1t h\u00ecnh <em>Animation</em></p><p class=\"el-desc\">Staging, blocking, camera \u2014 d\u00f9ng nguy\u00ean l\u00fd li\u00ean t\u1ee5c v\u00e0 ti\u00eau \u0111i\u1ec3m.</p></div>\r\n    <div class=\"el-item-img\" data-wipe><img src=\"/img/nguyen-ly-thi-giac/el-03-animation.png\" alt=\"Ho\u1ea1t h\u00ecnh\" loading=\"lazy\" decoding=\"async\" /></div>\r\n  </div>\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\"><span class=\"el-n\">04</span><p class=\"el-name\">Nhi\u1ebfp \u1ea3nh <em>Photography</em></p><p class=\"el-desc\">Framing, depth of field, rule of thirds \u2014 \u0111\u1ec1u l\u00e0 Gestalt.</p></div>\r\n    <div class=\"el-item-img\" data-wipe><img src=\"/img/nguyen-ly-thi-giac/el-04-photography.jpg\" alt=\"Nhi\u1ebfp \u1ea3nh\" loading=\"lazy\" decoding=\"async\" /></div>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"tips\">\r\n  <div class=\"tip\"><span class=\"tip-n\">01</span><div class=\"tip-c\"><p class=\"tip-t\">Dùng squint test</p><p class=\"tip-d\">Nheo mắt nhìn bài — nếu vẫn thấy rõ điểm nhấn và bố cục, bài đang dùng nguyên lý đúng.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">02</span><div class=\"tip-c\"><p class=\"tip-t\">Phân tích bài của bậc thầy</p><p class=\"tip-d\">Tìm 1 bức tranh bạn thích, gắn tên từng nguyên lý vào. Luyện mắt phân tích.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">03</span><div class=\"tip-c\"><p class=\"tip-t\">Lật ngược bài mình</p><p class=\"tip-d\">Nhìn bài qua gương hoặc lộn ngược. Nếu vẫn cân bằng, bố cục đang ổn.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">04</span><div class=\"tip-c\"><p class=\"tip-t\">Đếm điểm nhấn</p><p class=\"tip-d\">Một bài tốt chỉ có 1 điểm nhấn chính. Nhiều hơn 2 là mắt không biết nhìn đâu.</p></div></div>\r\n</div>\r\n\r\n<div class=\"dd break-half\">\r\n  <div class=\"dd-col good\">\r\n    <div class=\"dd-head\"><span class=\"dd-badge\">+</span><span class=\"dd-title\">Nên làm</span></div>\r\n    <ul class=\"dd-list\">\r\n      <li>Đặt câu hỏi \"tại sao\" cho mọi quyết định thị giác</li>\r\n      <li>Học phân tích bài trước khi học kỹ thuật mới</li>\r\n      <li>Xem bài của mình ở kích thước nhỏ (thumbnail)</li>\r\n      <li>Chia sẻ bài để người khác chỉ ra điểm chưa ổn</li>\r\n    </ul>\r\n  </div>\r\n  <div class=\"dd-col bad\">\r\n    <div class=\"dd-head\"><span class=\"dd-badge\">−</span><span class=\"dd-title\">Nên tránh</span></div>\r\n    <ul class=\"dd-list\">\r\n      <li>Cho rằng \"tôi vẽ theo cảm hứng\" là đủ</li>\r\n      <li>Bỏ qua việc nghiên cứu tranh của họa sĩ khác</li>\r\n      <li>Chỉ đánh giá bài ở kích thước zoom 100%</li>\r\n      <li>Áp dụng nguyên lý như công thức cứng</li>\r\n    </ul>\r\n  </div>\r\n</div>\r\n\r\n\r\n<!-- 05 · UNG DUNG -->\r\n<div class=\"div-sec\" id=\"sec-5\">\r\n  <div class=\"div-num\"><em>05</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Ứng dụng</p>\r\n    <h2 class=\"div-title\">Ba môn thực hành</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Lỽ thuyết cơ sở tạo hình không đứng một mình. Nó là đầu vào trực tiếp cho 3 môn thực hành trọng yếu:</p>\r\n\r\n<div class=\"subj-row break-half\">\r\n  <div class=\"subj hh\" style=\"background-image:url(/img/co-so-tao-hinh/subj-01-hh.jpg);background-size:cover;background-position:center\">\r\n    <span class=\"subj-tag\">Khối V</span>\r\n    <h4>Hình họa</h4>\r\n  </div>\r\n  <div class=\"subj tt\" style=\"background-image:url(/img/co-so-tao-hinh/subj-02-bc.png);background-size:cover;background-position:center\">\r\n    <span class=\"subj-tag\">Khối H</span>\r\n    <h4>Bố cục màu</h4>\r\n  </div>\r\n  <div class=\"subj tt\" style=\"background-image:url(/img/co-so-tao-hinh/subj-03-tt.jpg);background-size:cover;background-position:center\">\r\n    <span class=\"subj-tag\">Nền tảng</span>\r\n    <h4>Trang trí màu</h4>\r\n  </div>\r\n</div>\r\n\r\n<!-- 06 · LO TRINH -->\r\n<div class=\"div-sec\" id=\"sec-6\">\r\n  <div class=\"div-num\"><em>06</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Lộ trình</p>\r\n    <h2 class=\"div-title\">12–24 tháng luyện thi</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Với học sinh chuẩn bị thi khối H, V, lộ trình hợp lý kéo dài <strong>12–24 tháng</strong>:</p>\r\n\r\n<div class=\"tl\">\r\n  <div class=\"tl-item s1\">\r\n    <p class=\"tl-label\">Giai đợan 1 · 3 tháng</p>\r\n    <h4 class=\"tl-title\">Nhập môn</h4>\r\n    <p class=\"tl-desc\">Làm quen yếu tố cơ bản qua bài tập đường nét, hình khối đơn giản. Rèn thói quen quan sát tứ lệ, nhìn sáng tối.</p>\r\n  </div>\r\n  <div class=\"tl-item s2\">\r\n    <p class=\"tl-label\">Giai đợan 2 · 6–12 tháng</p>\r\n    <h4 class=\"tl-title\">Chuyên sâu</h4>\r\n    <p class=\"tl-desc\">Tách nhánh theo mục tiêu. Khối V tập trung tĩnh vật, tượng, người mẫu. Khối H tập trung trang trí màu và sáng tác bố cục.</p>\r\n  </div>\r\n  <div class=\"tl-item s3\">\r\n    <p class=\"tl-label\">Giai đợan 3 · 3–6 tháng</p>\r\n    <h4 class=\"tl-title\">Luyện thi</h4>\r\n    <p class=\"tl-desc\">Làm đề cấu trúc thi thật, luyện tốc độ, chấm chéo, phản biện giảng viên.</p>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"key break\">\r\n  <p class=\"key-lbl\">⭐ Điểm mấu chốt</p>\r\n  <p class=\"key-t\">Nguyên lý thị giác là <em>ngôn ngữ mẹ đẻ của mắt.</em></p>\r\n  <p class=\"key-d\">Bạn không cần học để dùng — mắt đã dùng từ khi bạn biết nhìn. Học chỉ để gọi tên và áp dụng có chủ đích. Một khi nắm được, bạn nhìn tác phẩm của người khác bằng cặp mắt mới — phân tích được, không chỉ cảm nhận được.</p>\r\n</div>\r\n\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>05</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">FAQ</p>\r\n    <h2 class=\"div-title\">Câu hỏi thường gặp</h2>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"faq\">\r\n  <details open>\r\n    <summary>Có cần học thuộc hết nguyên lý không?<span class=\"faq-icon\">−</span></summary>\r\n    <p>Không cần học thuộc như lý thuyết. Quan trọng là nhận diện được chúng trong tác phẩm và biết áp dụng khi cần. Luyện mắt quan trọng hơn học thuộc.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Nguyên lý thị giác và bố cục khác nhau thế nào?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Nguyên lý thị giác là <em>quy luật tự nhiên</em> của mắt. Bố cục là <em>kỹ thuật sắp xếp</em> dựa trên những quy luật đó. Bố cục là ứng dụng, nguyên lý là nền tảng.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Làm sao biết mình đang dùng đúng nguyên lý?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Hai dấu hiệu: (1) bài nhìn rõ điểm nhấn ngay từ cái nhìn đầu tiên, (2) mắt người xem đi theo đường dẫn bạn muốn.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Nguyên lý có thay đổi theo văn hóa không?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Các nguyên lý Gestalt cốt lõi là phổ quát vì gắn với sinh học mắt người. Nhưng một số quy ước mang tính văn hóa — ví dụ hướng đọc trái→phải ở phương Tây — thì có khác biệt.</p>\r\n  </details>\r\n</div>\r\n";

